using System;
using System.Collections.Generic;
using System.Linq;
using GTA;
using GTA.Math;
using GTA.Native;
using ModProject.LiveStudio;

namespace ModProject
{
    public class Mod : Script
    {
        private LiveStudioClient _client;
        private List<Vehicle> _spawnedVehicles = new List<Vehicle>();
        private int _lastPingTick = 0;
        private const int PingCooldownMs = 0;
        private const int MaxArmor = 100;
        private const int ArmorAmount = 25;

        public Mod()
        {
            Tick += OnTick;
            Aborted += OnAborted;

            _client = new LiveStudioClient(
                onEvent: HandleEvent,
                onLog: msg => MainThreadDispatcher.Enqueue(() => Notification.Show("~y~" + msg))
            );
            _client.Start();
        }

        private void OnTick(object sender, EventArgs e)
        {
            MainThreadDispatcher.DrainOnTick();
        }

        private void OnAborted(object sender, EventArgs e)
        {
            _client?.Dispose();
            foreach (var vehicle in _spawnedVehicles)
            {
                if (vehicle != null && vehicle.Exists())
                {
                    vehicle.Delete();
                }
            }
            _spawnedVehicles.Clear();
        }

        private void HandleEvent(LiveStudioEvent evt)
        {
            if (evt is ChatEvent chat)
            {
                HandleChat(chat);
            }
            else if (evt is GiftEvent gift)
            {
                HandleGift(gift);
            }
        }

        private void HandleChat(ChatEvent chat)
        {
            if (chat.Content.IndexOf("ping", StringComparison.OrdinalIgnoreCase) < 0)
                return;

            int currentTick = Game.GameTime;
            if (currentTick - _lastPingTick < PingCooldownMs)
                return;
            _lastPingTick = currentTick;

            MainThreadDispatcher.Enqueue(() =>
            {
                Ped player = Game.Player.Character;
                if (player == null || !player.Exists())
                    return;

                int newArmor = Math.Min(player.Armor + ArmorAmount, MaxArmor);
                player.Armor = newArmor;

                GTA.UI.Screen.ShowSubtitle("Viewer says PING! +25 armor", 3000);
            });
        }

        private void HandleGift(GiftEvent gift)
        {
            if (gift.GiftId != "rose")
                return;

            if (gift.RepeatEnd)
                return;

            MainThreadDispatcher.Enqueue(() =>
            {
                Ped player = Game.Player.Character;
                if (player == null || !player.Exists())
                    return;

                Vector3 spawnPos = player.Position + player.ForwardVector * 5.0f;
                float heading = player.Heading;

                Vector3 safePos = World.GetNextPositionOnStreet(spawnPos);
                if (safePos != Vector3.Zero)
                {
                    spawnPos = safePos;
                }

                Vehicle vehicle = World.CreateVehicle(VehicleHash.Police2, spawnPos, heading);
                if (vehicle == null || !vehicle.Exists())
                    return;

                vehicle.IsInvincible = true;
                vehicle.PlaceOnGround();
                vehicle.MarkAsNoLongerNeeded();

                _spawnedVehicles.Add(vehicle);
            });
        }
    }
}
